32	#[derive(Debug)]
33	pub(crate) struct KeyExprWireDeclaration {
34	    expr_id: ExprId,
35	    prefix_len: u32,
36	    session: WeakSession,
37	    undeclared: bool,
38	}
39	
40	impl KeyExprWireDeclaration {
41	    pub(crate) fn new(prefix: &str, session: &Session, force: bool) -> ZResult<Option<Self>> {
42	        let prefix_len = prefix.len() as u32;
43	        Ok(session
44	            .declare_prefix(prefix, force)
45	            .wait()?
46	            .map(|expr_id| Self {
47	                expr_id,
48	                prefix_len,
49	                session: session.downgrade(),
50	                undeclared: false,
51	            }))
52	    }
53	
54	    pub(crate) fn undeclare(&mut self) -> ZResult<()> {
55	        if self.undeclared {
56	            Ok(())
57	        } else {
58	            self.undeclared = true;
59	            self.session.undeclare_prefix(self.expr_id)
60	        }
61	    }
62	}
63	
64	impl Drop for KeyExprWireDeclaration {
65	    fn drop(&mut self) {
66	        let _ = self.undeclare();
67	    }
68	}
