82	/// A possibly-owned version of [`keyexpr`] that may carry optimisations for use with a [`Session`] that may have declared it.
83	///
84	/// Check [`keyexpr`]'s documentation for detailed explanations of the Key Expression Language.
85	#[repr(transparent)]
86	#[derive(Clone, serde::Deserialize, serde::Serialize)]
87	#[serde(from = "OwnedKeyExpr")]
88	#[serde(into = "OwnedKeyExpr")]
89	pub struct KeyExpr<'a>(pub(crate) KeyExprInner<'a>);
