107	impl KeyExpr<'static> {
108	    /// Constructs a [`KeyExpr`] without checking [`keyexpr`]'s invariants
109	    /// # Safety
110	    /// Key Expressions must follow some rules to be accepted by a Zenoh network.
111	    /// Messages addressed with invalid key expressions will be dropped.
112	    pub unsafe fn from_string_unchecked(s: String) -> Self {
113	        Self(KeyExprInner::Owned {
114	            // SAFETY: caller upholds key expression invariants for `s`.
115	            key_expr: unsafe { OwnedKeyExpr::from_string_unchecked(s) },
116	            declaration: None,
117	        })
118	    }
