136	impl<'a> KeyExpr<'a> {
137	    /// Equivalent to `<KeyExpr as TryFrom>::try_from(t)`.
138	    ///
139	    /// Will return an Err if `t` isn't a valid key expression.
140	    /// Note that to be considered a valid key expression, a string MUST be canon.
141	    ///
142	    /// [`KeyExpr::autocanonize`] is an alternative constructor that will canonize the passed expression before constructing it.
143	    pub fn new<T, E>(t: T) -> Result<Self, E>
144	    where
145	        Self: TryFrom<T, Error = E>,
146	    {
147	        Self::try_from(t)
148	    }
149	
150	    /// Constructs a key expression object to be used as a dummy value
151	    /// for empty objects. This method is not supposed to be called in user code,
152	    /// but may be used in language bindings (zenoh-c)
153	    #[zenoh_macros::internal]
154	    pub fn dummy() -> Self {
155	        Self(KeyExprInner::Borrowed {
156	            key_expr: KEYEXPR_DUMMY,
157	            declaration: None,
158	        })
159	    }
160	
161	    /// Checks if the key expression is the dummy one.
162	    /// This method is not supposed to be called in user code,
163	    /// but may be used in language bindings (zenoh-c)
164	    #[zenoh_macros::internal]
165	    pub fn is_dummy(&self) -> bool {
166	        let Self(inner) = self;
167	        let KeyExprInner::Borrowed { key_expr, .. } = inner else {
168	            return false;
169	        };
170	        std::ptr::eq(*key_expr, KEYEXPR_DUMMY)
171	    }
172	
173	    /// Constructs a new [`KeyExpr`] aliasing `self`.
174	    ///
175	    /// Note that [`KeyExpr`] (as well as [`OwnedKeyExpr`]) use reference counters internally, so you're probably better off using clone.
176	    pub fn borrowing_clone(&'a self) -> Self {
177	        let inner = match &self.0 {
178	            KeyExprInner::Borrowed {
179	                key_expr,
180	                declaration,
181	            } => KeyExprInner::Borrowed {
182	                key_expr,
183	                declaration: declaration.clone(),
184	            },
185	            KeyExprInner::Owned {
186	                key_expr,
187	                declaration,
188	            } => KeyExprInner::Borrowed {
189	                key_expr,
190	                declaration: declaration.clone(),
191	            },
192	        };
193	        Self(inner)
194	    }
195	
196	    /// Canonizes the passed value before returning it as a `KeyExpr`.
197	    ///
198	    /// Will return Err if the passed value isn't a valid key expression despite canonization.
199	    pub fn autocanonize<T, E>(mut t: T) -> Result<Self, E>
200	    where
201	        Self: TryFrom<T, Error = E>,
202	        T: Canonize,
203	    {
204	        t.canonize();
205	        Self::new(t)
206	    }
207	
208	    /// Constructs a [`KeyExpr`] without checking [`keyexpr`]'s invariants
209	    /// # Safety
210	    /// Key Expressions must follow some rules to be accepted by a Zenoh network.
211	    /// Messages addressed with invalid key expressions will be dropped.
212	    pub unsafe fn from_str_unchecked(s: &'a str) -> Self {
213	        // SAFETY: caller upholds key expression invariants for `s`.
214	        unsafe { keyexpr::from_str_unchecked(s).into() }
215	    }
216	
217	    /// Returns the borrowed version of `self`
218	    pub fn as_keyexpr(&self) -> &keyexpr {
219	        self
220	    }
221	
222	    /// Ensures `self` owns all of its data, and informs rustc that it does.
223	    pub fn into_owned(self) -> KeyExpr<'static> {
224	        let inner = match self.0 {
225	            KeyExprInner::Borrowed {
226	                key_expr,
227	                declaration,
228	            } => KeyExprInner::Owned {
229	                key_expr: key_expr.into(),
230	                declaration: declaration.clone(),
231	            },
232	            KeyExprInner::Owned {
233	                key_expr,
234	                declaration,
235	            } => KeyExprInner::Owned {
236	                key_expr,
237	                declaration,
238	            },
239	        };
240	        KeyExpr(inner)
241	    }
242	
243	    /// Joins both sides, inserting a `/` in between them.
244	    ///
245	    /// This should be your preferred method when concatenating path segments.
246	    ///
247	    /// # Examples
248	    /// ```
249	    /// # use std::convert::TryFrom;
250	    /// # use zenoh::key_expr::KeyExpr;
251	    /// let prefix = KeyExpr::try_from("some/prefix").unwrap();
252	    /// let suffix = KeyExpr::try_from("some/suffix").unwrap();
253	    /// let join = prefix.join(&suffix).unwrap();
254	    /// assert_eq!(join.as_str(), "some/prefix/some/suffix");
255	    /// ```
256	    pub fn join<S: AsRef<str> + ?Sized>(&self, s: &S) -> ZResult<KeyExpr<'static>> {
257	        Ok(KeyExpr(KeyExprInner::Owned {
258	            key_expr: self.as_keyexpr().join(s)?,
259	            declaration: self.declaration().clone(),
260	        }))
261	    }
262	
263	    /// Performs string concatenation and returns the result as a [`KeyExpr`] if possible.
264	    ///
265	    /// You should probably prefer [`KeyExpr::join`] as Zenoh may then take advantage of the hierarchical separation it inserts.
266	    pub fn concat<S: AsRef<str> + ?Sized>(&self, s: &S) -> ZResult<KeyExpr<'static>> {
267	        let s = s.as_ref();
268	        if self.ends_with('*') && s.starts_with('*') {
269	            bail!("Tried to concatenate {} (ends with *) and {} (starts with *), which would likely have caused bugs. If you're sure you want to do this, concatenate these into a string and then try to convert.", self, s)
270	        }
271	        Ok(KeyExpr(KeyExprInner::Owned {
272	            key_expr: OwnedKeyExpr::try_from(format!("{self}{s}"))?,
273	            declaration: self.declaration().clone(),
274	        }))
275	    }
276	
277	    /// Will return false and log an error in case of a `TryInto` failure.
278	    #[inline]
279	    #[allow(dead_code)]
280	    pub(crate) fn keyexpr_include<'b, L, R>(left: L, right: R) -> bool
281	    where
282	        L: TryInto<KeyExpr<'a>>,
283	        R: TryInto<KeyExpr<'b>>,
284	        L::Error: std::fmt::Display,
285	        R::Error: std::fmt::Display,
286	    {
287	        match left.try_into() {
288	            Ok(l) => match right.try_into() {
289	                Ok(r) => {
290	                    return l.includes(&r);
291	                }
292	                Err(e) => {
293	                    tracing::error!("{e}");
294	                }
295	            },
296	            Err(e) => {
297	                tracing::error!("{e}");
298	            }
299	        }
300	        false
301	    }
302	}
