461	    fn declaration(&self) -> &Option<Arc<KeyExprWireDeclaration>> {
462	        match &self.0 {
463	            KeyExprInner::Borrowed { declaration, .. } => declaration,
464	            KeyExprInner::Owned { declaration, .. } => declaration,
