475	    pub(crate) fn declare(mut self, session: &Session, force: bool) -> ZResult<Self> {
476	        if !self.is_fully_optimized(session) {
477	            *self.declaration_mut() =
478	                KeyExprWireDeclaration::new(self.as_str(), session, force)?.map(Arc::new);
479	        }
480	        Ok(self)
481	    }
482	
483	    pub(crate) fn declare_nonwild_prefix(
484	        mut self,
485	        session: &Session,
486	        force: bool,
487	    ) -> ZResult<Self> {
488	        if !self.is_non_wild_prefix_optimized(session) {
489	            let ke = self.as_keyexpr();
490	            *self.declaration_mut() = match ke.get_nonwild_prefix() {
491	                Some(prefix) => {
492	                    KeyExprWireDeclaration::new(prefix.as_str(), session, force)?.map(Arc::new)
493	                }
494	                None => None,
495	            }
496	        }
497	        Ok(self)
498	    }
