500	    fn into_declaration(self) -> Option<Arc<KeyExprWireDeclaration>> {
501	        match self.0 {
502	            KeyExprInner::Borrowed { declaration, .. } => declaration,
503	            KeyExprInner::Owned { declaration, .. } => declaration,
504	        }
505	    }
