507	    pub(crate) fn key_expr(&self) -> &keyexpr {
508	        match &self.0 {
509	            KeyExprInner::Borrowed { key_expr, .. } => key_expr,
510	            KeyExprInner::Owned { key_expr, .. } => key_expr,
511	        }
512	    }
513	
514	    pub(crate) fn is_fully_optimized(&self, session: &Session) -> bool {
515	        self.declaration()
516	            .as_ref()
517	            .map(|d| d.session == *session && d.prefix_len as usize == self.key_expr().len())
518	            .unwrap_or(false)
519	    }
520	
521	    pub(crate) fn is_non_wild_prefix_optimized(&self, session: &Session) -> bool {
522	        self.declaration()
523	            .as_ref()
524	            .map(|d| {
525	                d.session == *session
526	                    && self
527	                        .key_expr()
528	                        .get_nonwild_prefix()
529	                        .map(|p| p.len() == d.prefix_len as usize)
530	                        .unwrap_or(d.prefix_len == 0)
531	            })
532	            .unwrap_or(false)
533	    }
534	
535	    fn to_wire_inner(&'a self, session: &Session, mapping: Mapping) -> WireExpr<'a> {
536	        match self.declaration() {
537	            Some(d) if d.session == *session => WireExpr {
538	                scope: d.expr_id,
539	                suffix: std::borrow::Cow::Borrowed(
540	                    &self.key_expr().as_str()[(d.prefix_len as usize)..],
541	                ),
542	                mapping,
543	            },
544	            _ => WireExpr {
545	                scope: 0,
546	                suffix: std::borrow::Cow::Borrowed(self.key_expr().as_str()),
547	                mapping,
548	            },
549	        }
550	    }
551	
552	    pub(crate) fn to_wire(&'a self, session: &Session) -> WireExpr<'a> {
553	        self.to_wire_inner(session, Mapping::Sender)
554	    }
555	
556	    pub(crate) fn to_wire_local(&'a self, session: &Session) -> WireExpr<'a> {
557	        self.to_wire_inner(session, Mapping::Receiver)
558	    }
559	
560	    fn undeclare_with_session_check(&mut self, parent_session: Option<&Session>) -> ZResult<()> {
561	        match self.declaration_mut().take() {
562	            Some(mut d) if self.key_expr().len() == d.prefix_len as usize => {
563	                if parent_session.is_some_and(|s| d.session == *s) {
564	                    Arc::get_mut(&mut d).map(|d| d.undeclare()).unwrap_or(Ok(()))
565	                } else {
566	                    let expr_id = self.declaration_mut().insert(d).expr_id;
567	                        Err(zerror!(
568	                            "Failed to undeclare expr with id {}, as it was declared by another Session",
569	                            expr_id
570	                        )
571	                        .into())
572	                }
573	            },
574	            _ => Err(zerror!("Failed to undeclare {}, make sure you use the result of `Session::declare_keyexpr` to call `Session::undeclare`, and that key_expression was not undeclared previously", self).into()),
575	        }
576	    }
577	}
