590	/// A [`Resolvable`] returned by [`Session::undeclare`] when undeclaring a [`KeyExpr`]
591	///
592	/// # Examples
593	/// ```
594	/// # #[tokio::main]
595	/// # async fn main() {
596	///
597	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
598	/// let key_expr = session.declare_keyexpr("key/expression").await.unwrap();
599	/// session.undeclare(key_expr).await.unwrap();
600	/// # }
601	/// ```
602	#[must_use = "Resolvables do nothing unless you resolve them using `.await` or `zenoh::Wait::wait`"]
603	pub struct KeyExprUndeclaration<'a> {
604	    session: &'a Session,
605	    expr: KeyExpr<'a>,
606	}
