608	impl fmt::Debug for KeyExprUndeclaration<'_> {
609	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
610	        f.debug_struct("KeyExprUndeclaration")
611	            .field("session", &"..")
