52	            }
53	            // Handle chunks with only repeated "$*"
54	            [b'$', b'*', b'$', b'*', ..] => {
55	                index += 2;
56	            }
57	            _ => {
58	                if double_wild && &bytes[index..] != b"**" {
59	                    bytes[written..written + 3].copy_from_slice(b"**/");
